// ── Validate incoming payload ──────────────────────────────────────────────
const body = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const required = [
  'requestId', 'selectedDocumentType', 'documentSide',
  'imageBase64', 'profile.legalFirstName', 'profile.legalLastName', 'profile.dateOfBirth'
];
const allowed = {
  selectedDocumentType: ['drivers-license','state-id','passport','passport-card','permanent-resident-card','employment-authorization-card','military-id','unknown'],
  documentSide: ['front','back']
};
const missing = [];
for (const path of required) {
  const val = path.split('.').reduce((o, k) => (o && o[k] !== undefined ? o[k] : undefined), body);
  if (val === undefined || val === null || val === '') missing.push(path);
}
const invalid = [];
if (body.selectedDocumentType && !allowed.selectedDocumentType.includes(body.selectedDocumentType)) invalid.push('selectedDocumentType');
if (body.documentSide && !allowed.documentSide.includes(body.documentSide)) invalid.push('documentSide');
if (missing.length || invalid.length) {
  return [{ json: { valid: false, response: { success: false, requestId: body.requestId || null, error: { code: 'INVALID_REQUEST', message: 'Missing or invalid fields.', missing, invalid }, analysis: null } } }];
}
return [{ json: { ...body, valid: true } }];

// ── Decode base64 to binary ────────────────────────────────────────────────
const input = $json;
const raw = String(input.imageBase64 || '');
const match = raw.match(/^data:(.*?);base64,(.*)$/);
const mimeType = match ? (match[1] || 'image/png') : 'image/png';
const base64 = match ? match[2] : raw;
const extByMime = { 'image/jpeg': 'jpg', 'image/jpg': 'jpg', 'image/png': 'png', 'image/webp': 'webp' };
const ext = extByMime[mimeType] || 'png';
const fileName = `${input.requestId}-${input.selectedDocumentType}-${input.documentSide}.${ext}`;
const buffer = Buffer.from(base64, 'base64');
if (!buffer.length) throw new Error('imageBase64 decoded to empty buffer');
const binary = await this.helpers.prepareBinaryData(buffer, fileName, mimeType);
return [{
  json: {
    ...input,
    mimeType,
    fileName,
    imageDataUrl: raw.startsWith('data:') ? raw : `data:${mimeType};base64,${base64}`
  },
  binary: { image: binary }
}];

// ── Parse + validate GPT response ─────────────────────────────────────────
const original = $items('Build GPT Prompt')[0].json;
const response = $json;

function extractText(r) {
  if (typeof r.output_text === 'string') return r.output_text;
  if (Array.isArray(r.output)) {
    const parts = [];
    for (const item of r.output) {
      if (Array.isArray(item.content)) {
        for (const c of item.content) {
          if (typeof c.text === 'string')        parts.push(c.text);
          if (typeof c.output_text === 'string') parts.push(c.output_text);
        }
      }
    }
    if (parts.length) return parts.join('\n');
  }
  if (typeof r.text    === 'string') return r.text;
  if (typeof r.message === 'string') return r.message;
  return '';
}

function safeFailure(reason) {
  return {
    success: false, requestId: original.requestId,
    source: 'n8n-chatgpt-vision-v2',
    googleDriveFileId: original.googleDriveFileId || null,
    userMessage: 'We could not verify this image automatically. Please try again.',
    nextAction: 'HALT_VERIFICATION', canContinue: false, humanReviewRequired: true,
    analysis: {
      requestId: original.requestId, rawOcrText: null, documentDetected: false,
      booleanChecks: {
        documentDetected: false, supportedDocumentType: false,
        documentTypeMatchesSelection: false, sideMatchesSelection: false,
        frontImageRequired: true, backImageRequired: false,
        nameExtracted: false, dobExtracted: false,
        nameMatchesProfile: false, dobMatchesProfile: false,
        documentExpired: false, documentExpiresSoon: false,
        imageQualityLow: true, glareDetected: false, croppedDocument: false,
        physicalDocumentLikely: false, digitalManipulationSuspected: false,
        humanReviewRequired: true, canContinue: false
      },
      flags: [{ severity: 'CRITICAL', code: 'MODEL_RESPONSE_INVALID',
        message: 'The verifier could not return a valid structured response.' }],
      complianceEligibility: false, nextAction: 'HALT_VERIFICATION',
      humanReviewRequired: true, reviewReason: reason,
      userMessage: 'We could not verify this image automatically. Please try again.'
    }
  };
}

let raw = extractText(response).trim();
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();

let analysis;
try { analysis = JSON.parse(raw); }
catch (e) { return [{ json: safeFailure(`Invalid JSON: ${e.message}`) }]; }

const requiredKeys = [
  'requestId','rawOcrText','documentDetected','detectedDocumentType',
  'detectedSide','extractedFields','booleanChecks','flags','nextAction','userMessage',
  'nameCompare','dobCompare','expiryCheck'
];
const missing = requiredKeys.filter(k => !(k in analysis));
if (missing.length) return [{ json: safeFailure(`Model missing keys: ${missing.join(', ')}`) }];

if (analysis.requestId !== original.requestId) analysis.requestId = original.requestId;

const bc = analysis.booleanChecks || {};
const wrapper = {
  success: true,
  requestId: original.requestId,
  source: 'n8n-chatgpt-vision-v2',
  googleDriveFileId: original.googleDriveFileId || null,
  userMessage: analysis.userMessage || '',
  nextAction: analysis.nextAction || 'HALT_VERIFICATION',
  canContinue: Boolean(bc.canContinue),
  humanReviewRequired: Boolean(analysis.humanReviewRequired || bc.humanReviewRequired),
  // ── top-level compare results for easy access ──
  nameCompare: analysis.nameCompare || 'NOT_CHECKED',
  dobCompare:  analysis.dobCompare  || 'NOT_CHECKED',
  expiryCheck: analysis.expiryCheck || 'NOT_FOUND',
  analysis
};
return [{ json: wrapper }];

// ── Build final boolean summary + user-facing messages ────────────────────
// Every check is resolved here so the app only needs to read this object.
const r = $json;
const a = r.analysis || {};
const bc = a.booleanChecks || {};
const flags = a.flags || [];
const ef = a.extractedFields || {};

const flagCodes = flags.map(f => f.code);

// ── Boolean summary (flat, easy to read in app or logs) ───────────────────
const checks = {
  documentDetected:               Boolean(bc.documentDetected),
  supportedDocumentType:          Boolean(bc.supportedDocumentType),
  documentTypeMatchesSelection:   Boolean(bc.documentTypeMatchesSelection),
  sideMatchesSelection:           Boolean(bc.sideMatchesSelection),
  nameExtracted:                  Boolean(bc.nameExtracted),
  dobExtracted:                   Boolean(bc.dobExtracted),
  nameMatchesProfile:             Boolean(bc.nameMatchesProfile),
  dobMatchesProfile:              Boolean(bc.dobMatchesProfile),
  documentExpired:                Boolean(bc.documentExpired),
  documentExpiresSoon:            Boolean(bc.documentExpiresSoon),
  imageQualityLow:                Boolean(bc.imageQualityLow),
  glareDetected:                  Boolean(bc.glareDetected),
  croppedDocument:                Boolean(bc.croppedDocument),
  physicalDocumentLikely:         Boolean(bc.physicalDocumentLikely),
  digitalManipulationSuspected:   Boolean(bc.digitalManipulationSuspected),
  humanReviewRequired:            Boolean(bc.humanReviewRequired),
  canContinue:                    Boolean(bc.canContinue)
};

// ── Per-check user messages ────────────────────────────────────────────────
// Each message is shown ONLY when the check fails.
const messages = {};

if (!checks.documentDetected)
  messages.documentDetected = 'No supported US government ID was found in the image. Please upload a clear photo of your ID.';

if (checks.documentDetected && !checks.supportedDocumentType)
  messages.supportedDocumentType = 'This document type is not supported. Please use a US driver license, state ID, passport, passport card, permanent resident card, employment authorization card, or military ID.';

if (checks.documentDetected && !checks.documentTypeMatchesSelection) {
  const selected  = a.userSelectedTypeLabel  || a.userSelectedType  || 'the selected type';
  const detected  = a.detectedDocumentTypeLabel || a.detectedDocumentType || 'a different document';
  messages.documentTypeMatchesSelection = `You selected "${selected}" but the image looks like "${detected}". Please choose the correct document type or upload the right document.`;
}

if (checks.documentDetected && !checks.sideMatchesSelection) {
  const requested = a.userSelectedSide || 'the requested side';
  const found     = a.detectedSide     || 'the other side';
  messages.sideMatchesSelection = `The image shows the ${found} of the document but the ${requested} side was expected. Please upload the correct side.`;
}

if (!checks.nameExtracted)
  messages.nameExtracted = 'We could not read a name from the document. Please upload a clearer image.';

if (!checks.dobExtracted)
  messages.dobExtracted = 'We could not read the date of birth from the document. Please upload a clearer image.';

if (checks.nameExtracted && !checks.nameMatchesProfile) {
  const compare = r.nameCompare || a.nameCompare || '';
  messages.nameMatchesProfile = compare === 'PARTIAL_MATCH'
    ? 'The name on the document partially matches your profile. If this is your correct ID, please contact support.'
    : 'The name on the document does not match the name in your profile. Please go back and correct your legal name, or upload your own ID.';
}

if (checks.dobExtracted && !checks.dobMatchesProfile)
  messages.dobMatchesProfile = 'The date of birth on the document does not match your profile. Please go back and correct your date of birth, or upload your own ID.';

if (checks.documentExpired) {
  const expiry = ef.expiration_date || ef.card_expires || 'shown on document';
  messages.documentExpired = `This document expired on ${expiry}. Please provide a current, valid ID.`;
}

if (checks.documentExpiresSoon) {
  const expiry = ef.expiration_date || ef.card_expires || '';
  messages.documentExpiresSoon = `Your document expires soon${expiry ? ` (${expiry})` : ''}. You may want to renew it before starting work.`;
}

if (checks.imageQualityLow)
  messages.imageQualityLow = 'The image quality is too low to read the document clearly. Please retake in good lighting with sharp focus.';

if (checks.glareDetected)
  messages.glareDetected = 'Glare is obscuring part of the document. Please retake the photo without flash or bright reflections.';

if (checks.croppedDocument)
  messages.croppedDocument = 'The document appears to be cropped. Please capture the entire document within the frame.';

if (checks.digitalManipulationSuspected)
  messages.digitalManipulationSuspected = 'This image shows signs of digital editing. Please upload an unmodified photo of your physical ID.';

if (checks.humanReviewRequired && !messages.humanReviewRequired)
  messages.humanReviewRequired = 'This submission requires manual review. Our team will check your document and get back to you shortly.';

// ── Positive confirmation messages for passing checks ─────────────────────
const passing = {};
if (checks.documentDetected)             passing.documentDetected             = 'Document detected successfully.';
if (checks.documentTypeMatchesSelection) passing.documentTypeMatchesSelection = `Document type matches your selection (${a.detectedDocumentTypeLabel || a.detectedDocumentType || ''}).`;
if (checks.sideMatchesSelection)         passing.sideMatchesSelection         = `Correct document side (${a.detectedSide || ''}) confirmed.`;
if (checks.nameMatchesProfile)           passing.nameMatchesProfile           = 'Name matches your profile.';
if (checks.dobMatchesProfile)            passing.dobMatchesProfile            = 'Date of birth matches your profile.';
if (!checks.documentExpired && r.expiryCheck === 'VALID') passing.notExpired   = 'Document is valid and not expired.';
if (!checks.imageQualityLow)             passing.imageQualityOk              = 'Image quality is acceptable.';
if (checks.physicalDocumentLikely)       passing.physicalDocument             = 'Document appears to be a genuine physical ID.';

return [{ json: {
  ...r,
  booleanSummary: checks,
  failureMessages: messages,
  passingMessages: passing
} }];
